#!/usr/bin/env node
/* global console, process */
// Mirrors bin/gnode.js but with extra timestamps to break down the 210ms
// gap between bundle-direct and the wrapper.
//
// Stamps relative to `performance.timeOrigin` (process start ≈ 0):
//   t.preImports    just before module imports finish loading (top-of-file)
//   t.preEnableCC   before enableCompileCache()
//   t.postEnableCC  after enableCompileCache()
//   t.preMain       at main() entry
//   t.preBundleReq  before import(bundle.mjs)
//   t.postBundleReq after import resolves
//   t.preRunCli     before await runCli()
//   t.postRunCli    after await runCli() resolves

import { performance } from 'node:perf_hooks';
const t = {};
const stamp = (k) => { t[k] = performance.now(); };

stamp('preImports');

import { enableCompileCache, constants as moduleConstants } from 'node:module';
import { resolve, dirname } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';
import { tmpdir } from 'node:os';

stamp('preEnableCC');
const compileCacheDir =
  process.env.GNODE_COMPILE_CACHE_DIR ??
  process.env.NODE_COMPILE_CACHE ??
  resolve(tmpdir(), 'gnode-node-compile-cache');
const cc = enableCompileCache(compileCacheDir);
stamp('postEnableCC');

const here = dirname(fileURLToPath(import.meta.url));
const bundlePath = resolve(here, '../../dist/gnode/bridge-driver.bundle.mjs');

const forwardedArgv = process.argv.slice(2);
process.env.GNODE_TRUST_PREWARMED_BUNDLE ??= '1';

async function main() {
  stamp('preMain');
  stamp('preBundleReq');
  const bundle = await import(pathToFileURL(bundlePath).href);
  stamp('postBundleReq');
  stamp('preRunCli');
  const code = await bundle.runCli(forwardedArgv);
  stamp('postRunCli');

  const dt = (a, b) => Number((t[b] - t[a]).toFixed(2));
  process.stderr.write('\n[wrapper-probe]\n');
  process.stderr.write(JSON.stringify({
    abs: Object.fromEntries(Object.entries(t).map(([k, v]) => [k, Number(v.toFixed(2))])),
    deltas: {
      moduleImports:    dt('preImports',   'preEnableCC'),
      enableCompileCC:  dt('preEnableCC',  'postEnableCC'),
      ccToMain:         dt('postEnableCC', 'preMain'),
      mainToBundleReq:  dt('preMain',      'preBundleReq'),
      bundleRequire:    dt('preBundleReq', 'postBundleReq'),
      bundleReqToRun:   dt('postBundleReq','preRunCli'),
      runCli:           dt('preRunCli',    'postRunCli'),
      processStartToImports: Number(t.preImports.toFixed(2)),  // since perf.timeOrigin
    },
    totalSinceStart: Number(t.postRunCli.toFixed(2)),
    compileCache: {
      status: cc?.status,
      enabled:
        cc?.status === moduleConstants.compileCacheStatus.ENABLED ||
        cc?.status === moduleConstants.compileCacheStatus.ALREADY_ENABLED,
      directory: cc?.directory,
    },
  }, null, 2) + '\n');
  process.exitCode = code ?? 0;
}

main().catch((e) => {
  process.stderr.write(`${e?.stack ?? e}\n`);
  process.exitCode = 1;
});
